import ULThemeLogo from "@/components/ULThemeLogo";
import ULThemeSubtitle from "@/components/ULThemeSubtitle";
import ULThemeTitle from "@/components/ULThemeTitle";

import { useConsentManager } from "../hooks/useConsentManager";

function Header() {
  const { texts, locales, screen } = useConsentManager();

  const logoAltText = locales?.heading?.logoAltText;
  const title = texts?.title || locales?.heading?.title;
  const description = locales?.heading?.description;

  // App name from screen data
  const clientName = (screen as unknown as { clientName?: string })?.clientName;

  return (
    <>
      <ULThemeLogo altText={logoAltText} />
      <ULThemeTitle>{title}</ULThemeTitle>
      {clientName && (
        <ULThemeSubtitle>
          <strong>{clientName}</strong> {description}
        </ULThemeSubtitle>
      )}
      {!clientName && description && (
        <ULThemeSubtitle>{description}</ULThemeSubtitle>
      )}
    </>
  );
}

export default Header;
