import { useConsentManager } from "../hooks/useConsentManager";

function ScopesList() {
  const { locales, screen } = useConsentManager();

  // Get scopes from screen data
  const scopes = (screen as unknown as { scopes?: { value: string; description?: string }[] })?.scopes;

  if (!scopes || scopes.length === 0) {
    return (
      <p className="text-sm text-gray-500 text-center my-4">
        {locales?.scopes?.noScopes}
      </p>
    );
  }

  return (
    <div className="my-4">
      <p className="text-sm font-semibold text-body-text mb-2">
        {locales?.scopes?.title}
      </p>
      <ul className="space-y-2">
        {scopes.map((scope) => (
          <li
            key={scope.value}
            className="flex items-start gap-2 text-sm text-body-text"
          >
            <span className="mt-0.5 text-green-500 font-bold">✓</span>
            <span>
              <span className="font-medium">{scope.value}</span>
              {scope.description && (
                <span className="text-gray-500"> — {scope.description}</span>
              )}
            </span>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default ScopesList;
