import { ULThemeButton } from "@/components/ULThemeButton";

import { useConsentManager } from "../hooks/useConsentManager";

function ConsentActions() {
  const { locales, handleAccept, handleDeny } = useConsentManager();

  return (
    <div className="flex flex-col gap-3 mt-4">
      <ULThemeButton
        type="button"
        className="w-full"
        onClick={handleAccept}
      >
        {locales?.actions?.acceptButton}
      </ULThemeButton>
      <ULThemeButton
        type="button"
        className="w-full"
        variant="outline"
        onClick={handleDeny}
      >
        {locales?.actions?.denyButton}
      </ULThemeButton>
    </div>
  );
}

export default ConsentActions;
